        public async Task<IOBPv600GetTransactionsForBankAccountApiResponse> OBPv600GetTransactionsForBankAccountAsync(string bankid, string accountid, string viewid, System.Threading.CancellationToken cancellationToken = default)
        {
            UriBuilder uriBuilderLocalVar = new UriBuilder();

            try
            {
                ValidateOBPv600GetTransactionsForBankAccount(bankid, accountid, viewid);

                FormatOBPv600GetTransactionsForBankAccount(ref bankid, ref accountid, ref viewid);

                using (HttpRequestMessage httpRequestMessageLocalVar = new HttpRequestMessage())
                {
