                    uriBuilderLocalVar.Path = uriBuilderLocalVar.Path.Replace("%7Bviewid%7D", Uri.EscapeDataString(viewid.ToString()));

                    List<TokenBase> tokenBaseLocalVars = new List<TokenBase>();
